create table dirkspzm32.cal_cfg (
    calendar_id                 varchar2(32 char) default sys_guid() not null enable,
    cal_title_nls_key           varchar2(30 char) not null enable,
    appointment_edit_logic      varchar2(30 char),
    usage_system_id             varchar2(30 char),
    scheduler_logic             varchar2(30 char),
    edit_logic_ext_param_name   varchar2(30 char),
    cal_color                   number(*, 5),
    cmd_info_add_appointment    varchar2(1000 char),
    cmd_info_edit_appointment   varchar2(1000 char),
    cmd_info_delete_appointment varchar2(1000 char)
);

alter table dirkspzm32.cal_cfg
    add constraint pk_cal_cfg primary key ( calendar_id )
        using index enable;

alter table dirkspzm32.cal_cfg add constraint uk_cal_cfg_usage_system unique ( usage_system_id )
    using index enable;


